  @api util.setDigit(val, d, pos, base, half)  @ 216
  @api util.snapTo(v, dir, interval)  @ 223
      @contract  advances at least one full interval; values already on a boundary do not no-op
  @api util.nudgedScalar(v, lo, hi, dir, interval)  @ 228
